    strncpy(creds->wifi_ssid, DEFAULT_WIFI_SSID, MAX_CREDENTIAL_LEN - 1);
    strncpy(creds->wifi_password, DEFAULT_WIFI_PASSWORD, MAX_CREDENTIAL_LEN - 1);
