/* ============================================================
 * MAIN STREAMING LOOP
 * ============================================================ */

static cam_error_t streaming_loop(device_state_t *state, const device_credentials_t *creds) {
    unsigned char *frame_buffer = NULL;
    size_t frame_len = 0;
    cam_error_t err;
    unsigned long last_heartbeat = 0;
    unsigned long now;

    frame_buffer = (unsigned char *)malloc(STREAM_BUFFER_SIZE);
    if (!frame_buffer) {
        platform_log("ERROR", "Failed to allocate frame buffer (%d bytes)", STREAM_BUFFER_SIZE);
        return CAM_ERR_STREAM;
    }

    state->streaming = true;
    platform_log("INFO", "Starting video stream...");

    while (state->streaming) {
        now = platform_get_time_ms();

        /* Periodic heartbeat */
        if ((now - last_heartbeat) >= (HEARTBEAT_INTERVAL_S * 1000UL)) {
            err = cloud_send_heartbeat();
            if (err != CAM_OK) {
                platform_log("WARN", "Heartbeat failed, attempting reconnection...");
                state->cloud_connected = false;

                /* Attempt reconnection */
                while (!state->cloud_connected &&
                       state->reconnect_count < MAX_RECONNECT_ATTEMPTS) {
                    state->reconnect_count++;
                    platform_log("INFO", "Reconnect attempt %d/%d",
                                 state->reconnect_count, MAX_RECONNECT_ATTEMPTS);

                    if (!state->wifi_connected) {
                        connect_wifi(state, creds);
                    }
                    if (state->wifi_connected) {
                        connect_cloud(state, creds);
                    }

                    if (!state->cloud_connected) {
                        platform_delay_ms(RECONNECT_DELAY_MS);
                    }
                }

                if (!state->cloud_connected) {
                    platform_log("ERROR", "Max reconnection attempts reached. Stopping stream.");
                    state->streaming = false;
                    break;
                }
            }
            last_heartbeat = now;
        }

        /* Capture and send frame */
        err = camera_capture_frame(frame_buffer, STREAM_BUFFER_SIZE, &frame_len);
        if (err != CAM_OK) {
            platform_log("WARN", "Frame capture failed (err=%d), skipping frame.", err);
            platform_delay_ms(100);
            continue;
        }

        err = cloud_send_frame(frame_buffer, frame_len);
        if (err != CAM_OK) {
            platform_log("WARN", "Frame send failed (err=%d)", err);
            /* Will be handled by heartbeat reconnection logic */
        }
    }

    /* Clean up - securely clear frame buffer in case it contained sensitive imagery */
    if (frame_buffer) {
        secure_memzero(frame_buffer, STREAM_BUFFER_SIZE);
        free(frame_buffer);
    }

    return CAM_OK;
}

