    if (err != CAM_OK) {
        platform_log("FATAL", "WiFi connection failed. Halting.");
        secure_memzero(&credentials, sizeof(credentials));
        return (int)err;
    }

    /* Step 3: Connect and authenticate with cloud */
    err = connect_cloud(&state, &credentials);
    if (err != CAM_OK) {
        platform_log("FATAL", "Cloud authentication failed. Halting.");
        wifi_driver_disconnect();
        secure_memzero(&credentials, sizeof(credentials));
        return (int)err;
    }

    /* Step 4: Initialize camera hardware */
